import React from "react";
import { Link } from "react-router-dom";

const Navbar = () => {
  return (
    <nav className="navbar navbar-expand-lg sticky-top" style={{ backgroundColor: "#4CAF50", padding: "10px 15px" }}>
      <div className="container-fluid">
        <Link className="navbar-brand" to="/" style={{ color: "white", fontWeight: "bold", fontSize: "20px" }}>Agro Seva</Link>
        <button
          className="navbar-toggler"
          type="button"
          data-bs-toggle="collapse"
          data-bs-target="#navbarSupportedContent"
          aria-controls="navbarSupportedContent"
          aria-expanded="false"
          aria-label="Toggle navigation"
        >
          <span className="navbar-toggler-icon"></span>
        </button>
        <div className="collapse navbar-collapse" id="navbarSupportedContent">
          <ul className="navbar-nav me-auto mb-2 mb-lg-0">
            {["Home", "Weather", "Crop Rates", "Advisory", "Schemes", "About", "Contact"].map((item, index) => (
              <li className="nav-item" key={index}>
                <Link className="nav-link" to={`/${item.replace(" ", "")}`} style={{ color: "white", fontSize: "17px", marginRight: "15px", transition: "0.3s" }}>
                  {item}
                </Link>
              </li>
            ))}
          </ul>
          <form className="d-flex" role="search">
            <input className="form-control me-2" type="search" placeholder="Search" aria-label="Search" style={{ borderRadius: "5px", border: "1px solid white" }} />
            <button className="btn btn-light" type="submit" style={{ backgroundColor: "white", color: "#4CAF50", borderRadius: "5px" }}>Search</button>
          </form>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
